query StudentInfo($matrikelnummer: String!) {
  studentInfo(matrikelnummer: $matrikelnummer) {
    matrikelnummer
    vorname
    nachname
    studiengang
    semester
    notendurchschnitt
    anzahlBestandeneModule
    noten {
      id
      modulId
      modulName
      note
      status
      lehrendenMatrikelnummer
      erstelltAm
    }
  }
}

